import{_ as e,o as s,c as o,a2 as a}from"./chunks/framework.BWuWLRhz.js";const n="/assets/04-auth-priority-stack@2x.DwUH9K9L.png",k=JSON.parse('{"title":"04 · API 配置：订阅登录还是 API key，怎么选、怎么切","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/04-api-config.md","filePath":"claude-code/04-api-config.md"}'),d={name:"claude-code/04-api-config.md"};function i(p,t,l,r,c,h){return s(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="_04-·-api-配置-订阅登录还是-api-key-怎么选、怎么切" tabindex="-1">04 · API 配置：订阅登录还是 API key，怎么选、怎么切 <a class="header-anchor" href="#_04-·-api-配置-订阅登录还是-api-key-怎么选、怎么切" aria-label="Permalink to &quot;04 · API 配置：订阅登录还是 API key，怎么选、怎么切&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./03-how-it-works">03 · 它是怎么工作的</a> 拆了代理循环——Claude Code 怎么「想 → 做 → 看」。这一篇解决它跑起来的前提：<strong>用什么身份连上模型</strong>。下一篇讲接第三方 / 国产模型。</p></blockquote><p>2026 年 6 月，Claude Code 官方文档里列了整整 <strong>6 种身份验证方式</strong>，从订阅登录到云厂商凭证，优先级一层压一层。</p><p>这里有个很常见的坑，我自己就栽过。我那会儿图省事，早年在 <code>.zshrc</code> 里 export 过一个 <code>ANTHROPIC_API_KEY</code>，后来买了 Max 订阅、<code>/login</code> 登录得好好的，结果某天翻 Console 账单，发现 API 这边在持续扣钱——明明以为自己一直在用订阅额度。查了半天才搞明白：<strong>只要环境里有 API key，它的优先级就压过订阅</strong>。</p><p>说白了，「登进去了」不等于「用对了身份」。这一篇就把这件事讲透。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>订阅登录 vs API key 两条路的<strong>适用场景对照表</strong>，知道自己该走哪条</li><li>三种「在哪配、怎么改」的落地姿势（命令行登录 / 环境变量 / settings.json），以及 Mac / Windows / Linux 的差异</li><li>一套<strong>自查命令</strong>：用 <code>/status</code> 确认「我现在到底在用哪个身份、哪个模型」，再也不糊里糊涂被扣费</li></ul><hr><h2 id="_01-两种身份-订阅登录-vs-api-key" tabindex="-1">01 两种身份：订阅登录 vs API key <a class="header-anchor" href="#_01-两种身份-订阅登录-vs-api-key" aria-label="Permalink to &quot;01 两种身份：订阅登录 vs API key&quot;">​</a></h2><p>先给结论：<strong>个人自己用，选订阅登录；要嵌进脚本 / CI / 团队按用量结算，才用 API key。</strong></p><p>Claude Code 连模型，本质要回答一个问题：<strong>「凭什么让我用？」</strong> 这就是身份验证（authentication）——你得证明自己是谁、用谁的额度。官方支持的方式有好几种，但对小白来说，先抓住最主流的两条路就够。</p><p><strong>类比：进健身房。</strong> 订阅登录就像办了张<strong>月卡</strong>——刷脸进门，一个月内随便练，不按次计费；API key 则像<strong>按次买的门票</strong>——每进一次扣一张，用多少付多少。月卡适合天天去的人，门票适合偶尔来一次、或者帮朋友带人进场（脚本、自动化）的场景。</p><p>两条路的区别，一张表说清：</p><table tabindex="0"><thead><tr><th>维度</th><th>订阅登录（Claude.ai 账户）</th><th>API key（Console / 环境变量）</th></tr></thead><tbody><tr><td><strong>怎么连</strong></td><td>终端跑 <code>claude</code>，浏览器登录</td><td>配 <code>ANTHROPIC_API_KEY</code> 环境变量</td></tr><tr><td><strong>怎么计费</strong></td><td>按月订阅（Pro / Max / Team）</td><td>按 token 用量，从 Console 余额扣</td></tr><tr><td><strong>额度</strong></td><td>有用量上限，到顶要等刷新</td><td>充多少用多少，无固定上限</td></tr><tr><td><strong>适合谁</strong></td><td>个人日常交互式开发</td><td>脚本 / CI / 团队按量结算</td></tr><tr><td><strong>凭证从哪来</strong></td><td><code>/login</code> 浏览器授权</td><td><a href="https://platform.claude.com" target="_blank" rel="noreferrer">Claude Console</a> 创建 key</td></tr><tr><td><strong>能否无浏览器</strong></td><td>默认要浏览器（CI 用 <code>setup-token</code>）</td><td>能，纯环境变量即可</td></tr></tbody></table><p>订阅这边再细分一下，因为后面选模型会用到：</p><ul><li><strong>Claude Pro / Max</strong>：个人订阅，用 Claude.ai 账户登录。Pro 偏轻量，Max 额度大、能用上最强模型。</li><li><strong>Claude for Teams / Enterprise</strong>：团队套餐，管理员邀请你，统一计费。Enterprise 还能配 SSO、托管策略。</li></ul><p>个人项目一律走 Max 订阅登录，省心、不用盯余额；只有往 GitHub Actions 里塞自动化任务时，才单独搞一个 API key（具体到 CI 的玩法第 44 篇再讲）。<strong>日常开发别碰 API key，纯属给自己找扣费焦虑。</strong></p><blockquote><p>💡 一句话总结：<strong>订阅 = 月卡（个人日常），API key = 门票（脚本/团队按量）</strong>，先想清楚自己是哪种人，再去配。</p></blockquote><hr><h2 id="_02-订阅登录-最省心的那条路" tabindex="-1">02 订阅登录：最省心的那条路 <a class="header-anchor" href="#_02-订阅登录-最省心的那条路" aria-label="Permalink to &quot;02 订阅登录：最省心的那条路&quot;">​</a></h2><p>如果你是个人用户、买了 Pro 或 Max，那配置这事儿基本<strong>不用配</strong>——跑起来登录一下就行。</p><p><strong>操作就一步。</strong> 装好 Claude Code 后（装机看 <a href="./02-install">02 篇</a>），在终端敲：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p>首次启动，Claude Code 会自动<strong>打开浏览器</strong>让你登录 Claude.ai 账户。登录完浏览器会跳回终端，搞定。</p><p>几个真实会撞上的情况，提前说：</p><ul><li><strong>浏览器没自动弹出来？</strong> 在 Claude Code 界面按 <code>c</code>，它会把登录链接复制到剪贴板，你自己粘到浏览器打开。</li><li><strong>浏览器登录后给了一串「登录代码」、没跳回来？</strong> 把那串代码粘回终端的 <code>Paste code here if prompted</code> 提示符处。这种情况常见于 <strong>WSL2、SSH 远程会话、容器</strong>里——因为浏览器连不到本机的回调端口。</li><li><strong>想换账号 / 退出登录？</strong> 在 Claude Code 里输入 <code>/logout</code>，下次启动重新登。</li></ul><p><strong>登进去的凭证存哪了？</strong> 这点平台不一样，知道了排查问题才不抓瞎：</p><table tabindex="0"><thead><tr><th>平台</th><th>凭证存储位置</th></tr></thead><tbody><tr><td><strong>macOS</strong></td><td>加密的系统钥匙串（Keychain）</td></tr><tr><td><strong>Linux</strong></td><td><code>~/.claude/.credentials.json</code>（权限 <code>0600</code>）</td></tr><tr><td><strong>Windows</strong></td><td><code>%USERPROFILE%\\.claude\\.credentials.json</code>（继承用户目录权限）</td></tr></tbody></table><p>这些都是 Claude Code 通过 <code>/login</code> / <code>/logout</code> 自动管的，<strong>你不用手动碰</strong>。我自己在 Mac 上排查登录问题时，照着 Linux 的路子去翻 <code>~/.claude/.credentials.json</code>，结果死活找不到，一度怀疑没登录成功——原因就在这：macOS 根本没把它放成文件，而是塞进了 Keychain。</p><blockquote><p>💡 一句话总结：订阅用户 <strong>「跑 <code>claude</code> → 浏览器登录」就齐活</strong>，凭证 Claude Code 自动存好，别手动去翻。</p></blockquote><hr><h2 id="_03-api-key-脚本和团队的那条路" tabindex="-1">03 API key：脚本和团队的那条路 <a class="header-anchor" href="#_03-api-key-脚本和团队的那条路" aria-label="Permalink to &quot;03 API key：脚本和团队的那条路&quot;">​</a></h2><p>API key 这条路，适用面其实很窄——<strong>你不做自动化、不在团队里按量结算，基本用不上。</strong> 但既然要讲清楚「怎么切换」，就得先知道它长什么样。</p><p><strong>第一步，拿 key。</strong> 去 <a href="https://platform.claude.com" target="_blank" rel="noreferrer">Claude Console</a> 创建一个 API 密钥（这是 Anthropic 官方的开发者控制台，按 token 用量计费，和 Claude.ai 订阅是两套账）。</p><p><strong>第二步，配成环境变量。</strong> 平台命令不一样，分开说：</p><p>macOS / Linux：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ANTHROPIC_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sk-ant-你的密钥</span></span></code></pre></div><p>Windows（PowerShell，永久写入用户环境变量）：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ANTHROPIC_API_KEY&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;sk-ant-你的密钥&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">EnvironmentVariableTarget</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::User)</span></span></code></pre></div><blockquote><p>⚠️ <strong>密钥就是钱，别乱放。</strong> 不要把 key 写进代码、提交进 Git、贴进任何会被分享的文件。临时用 <code>export</code> 设在当前终端最稳，关掉就没了。要持久化就走系统环境变量，别硬编码到项目里。</p></blockquote><p><strong>第三步，启动确认。</strong> 设好后跑 <code>claude</code>，交互模式下系统会<strong>提示你批准一次</strong>这个 key（批准 / 拒绝二选一，选择会被记住）。批准后就用它跑。</p><p>这里有个官方明说的关键行为，也就是开头那个坑的根源：</p><blockquote><p><strong>如果你有活跃的 Claude 订阅，但环境里同时设了 <code>ANTHROPIC_API_KEY</code>，那么 API key 在批准后会优先。</strong> 如果这个 key 属于已禁用或过期的组织，还会直接导致验证失败。</p></blockquote><p>换句话说，<strong>API key 会「盖过」你的订阅</strong>。所以才有了下一节要讲的切换问题。</p><blockquote><p>💡 一句话总结：API key 走 <strong>Console 拿 key → 配环境变量 → 启动批准</strong> 三步；记住它一旦存在就<strong>优先于订阅</strong>，这是后面所有「切换」问题的根。</p></blockquote><hr><h2 id="_04-怎么切换-优先级才是真相" tabindex="-1">04 怎么切换：优先级才是真相 <a class="header-anchor" href="#_04-怎么切换-优先级才是真相" aria-label="Permalink to &quot;04 怎么切换：优先级才是真相&quot;">​</a></h2><p><strong>核心结论：你「以为在用哪个身份」不重要，Claude Code 的优先级顺序说了算。</strong> 想切换，本质就是去动这个优先级。</p><p><strong>类比：插座的接线顺序。</strong> 你家墙上有好几个插座（订阅、API key、云凭证……），电器到底从哪个取电，不看你心里想用哪个，看<strong>实际插着哪个、谁的位置更靠前</strong>。要换电源，就得把更靠前那个拔掉。</p><p>官方文档给的<strong>身份验证优先级</strong>，从高到低 6 层（高的会盖过低的）：</p><table tabindex="0"><thead><tr><th style="text-align:center;">优先级</th><th>凭证来源</th><th>典型场景</th></tr></thead><tbody><tr><td style="text-align:center;">1（最高）</td><td>云提供商（Bedrock / Vertex / Foundry）</td><td>企业走云厂商</td></tr><tr><td style="text-align:center;">2</td><td><code>ANTHROPIC_AUTH_TOKEN</code> 环境变量</td><td>走 LLM 网关 / 代理</td></tr><tr><td style="text-align:center;">3</td><td><code>ANTHROPIC_API_KEY</code> 环境变量</td><td>直连 Anthropic API</td></tr><tr><td style="text-align:center;">4</td><td><code>apiKeyHelper</code> 脚本输出</td><td>动态 / 轮换凭证</td></tr><tr><td style="text-align:center;">5</td><td><code>CLAUDE_CODE_OAUTH_TOKEN</code></td><td>CI 里用的长期令牌</td></tr><tr><td style="text-align:center;">6（最低）</td><td><code>/login</code> 的订阅凭证</td><td><strong>个人订阅默认走这层</strong></td></tr></tbody></table><p><img src="'+n+`" alt="身份验证优先级栈：Claude Code 从顶往下找第一个有值的层"></p><p>这张图把上面那张表「立」了起来：6 层凭证从高到低竖直堆叠，Claude Code 从栈顶往下扫，跳过所有「空」的层，停在第一个「有值」的层就用它——个人订阅场景下，上面 5 层都空，于是命中最底层的订阅登录。</p><p>看明白没？<strong>订阅在最底层。</strong> 所以只要上面任何一层有值，它就盖过你的订阅。这就解释了开头那个场景——明明登录了 Max，却在烧 API 的钱——因为第 3 层的 <code>ANTHROPIC_API_KEY</code> 压着第 6 层的订阅。</p><p><strong>那怎么切回订阅？</strong> 官方给的办法很直接——把更高优先级那层清掉：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ANTHROPIC_API_KEY</span></span></code></pre></div><p>然后跑 <code>/status</code> 确认。如果是交互模式里临时不想用某个 key，也可以走 <code>/config</code> 里的 <strong>「使用自定义 API 密钥」开关</strong> 关掉它。</p><p>反过来，<strong>从订阅切到 API key</strong>，就是 <code>export</code> 上 key、批准一次即可（见 03 节）。</p><p>几条容易踩的细节，一并记下：</p><ul><li><strong><code>ANTHROPIC_API_KEY</code> / <code>ANTHROPIC_AUTH_TOKEN</code> 只对终端 CLI 会话生效。</strong> Claude Desktop 桌面端和远程会话<strong>只认 OAuth 登录</strong>，不读这些环境变量。</li><li><strong>Claude Code on the Web（网页版）永远用你的订阅凭证</strong>，沙箱里的 API key 环境变量盖不过它。</li><li><code>ANTHROPIC_AUTH_TOKEN</code>（第 2 层）和 <code>ANTHROPIC_API_KEY</code>（第 3 层）是两个不同的东西：前者作为 <code>Authorization: Bearer</code> 头发送，走网关 / 代理时用；后者作为 <code>X-Api-Key</code> 头发送，直连官方 API 时用。<strong>别配混。</strong></li></ul><blockquote><p>💡 一句话总结：切换 = 调优先级。<strong>订阅在最底层，上面任何一层有值都会盖过它</strong>；切回订阅就 <code>unset</code> 掉高层那个，再用 <code>/status</code> 验。</p></blockquote><hr><h2 id="_05-模型选择基础-opus、sonnet-还是-default" tabindex="-1">05 模型选择基础：opus、sonnet 还是 default <a class="header-anchor" href="#_05-模型选择基础-opus、sonnet-还是-default" aria-label="Permalink to &quot;05 模型选择基础：opus、sonnet 还是 default&quot;">​</a></h2><p>身份配好了，还有一件事要拍板：<strong>让它用哪个模型干活。</strong></p><p><strong>类比：派活儿挑人。</strong> Opus 是组里<strong>最强的资深工程师</strong>——脑子好、推理深，但慢、贵；Sonnet 是<strong>主力干将</strong>——日常编程又快又稳，性价比高；Haiku 是<strong>跑腿小弟</strong>——简单活儿秒回、最省。难题派 Opus，日常派 Sonnet，杂活派 Haiku。</p><p>Claude Code 用<strong>模型别名</strong>让你不用记一长串版本号。常用这几个：</p><table tabindex="0"><thead><tr><th>别名</th><th>用途</th></tr></thead><tbody><tr><td><code>default</code></td><td>特殊值：清掉手动覆盖，回到你账户层级推荐的模型</td></tr><tr><td><code>opus</code></td><td>最新 Opus，复杂推理 / 架构决策</td></tr><tr><td><code>sonnet</code></td><td>最新 Sonnet，日常编程</td></tr><tr><td><code>haiku</code></td><td>快速高效，处理简单任务</td></tr><tr><td><code>best</code></td><td>当前等同于 <code>opus</code>，使用最强大的可用模型</td></tr><tr><td><code>opusplan</code></td><td>混合模式：Plan Mode 用 Opus 想，执行时切 Sonnet 干</td></tr><tr><td><code>opus[1m]</code> / <code>sonnet[1m]</code></td><td>带 100 万 token 上下文窗口，啃大代码库 / 长会话</td></tr></tbody></table><p>注意：<strong>别名指向「你的层级推荐的版本」，会随时间更新</strong>。具体解析成哪个版本，官方文档以它为准——比如在 Anthropic API 上 <code>opus</code> 当前解析为 Opus 4.8、<code>sonnet</code> 解析为 Sonnet 4.6，但不同提供商（Bedrock / Vertex 等）解析的版本不同（以官方文档为准，可能变化）。</p><p><strong>你订阅的层级，决定了默认给你哪个模型：</strong></p><table tabindex="0"><thead><tr><th>账户类型</th><th><code>default</code> 解析为</th></tr></thead><tbody><tr><td>Max / Team Premium / Enterprise 按量 / Anthropic API</td><td>Opus 4.8</td></tr><tr><td>Pro / Team Standard / Enterprise 订阅席位</td><td>Sonnet 4.6</td></tr></tbody></table><p>也就是说，<strong>Pro 用户默认是 Sonnet，Max 用户默认能上 Opus</strong>——这也是推荐重度用户上 Max 的原因之一。另外，达到 Opus 用量阈值时，Claude Code 可能会<strong>自动回退到 Sonnet</strong>，这是正常行为，不是 bug。</p><p><strong>怎么设模型？</strong> 官方按优先级给了四种方式：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 会话期间临时切（运行不带参数的 /model 会打开选择器）——优先级最高</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sonnet</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 启动时指定</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opus</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 环境变量（本会话生效）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ANTHROPIC_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">opus</span></span></code></pre></div><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 4. 写进 settings.json，永久作为新会话默认——优先级最低</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;opus&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>以上按优先级从高到低排列：会话内 <code>/model</code> &gt; 启动时 <code>--model</code> &gt; 环境变量 <code>ANTHROPIC_MODEL</code> &gt; settings 文件。一个实用的习惯：日常 <code>settings.json</code> 里固定 <code>sonnet</code>，碰到需要硬啃的架构问题，对话里临时 <code>/model opus</code> 顶上去，省额度。</p><blockquote><p>关于工作量级别（<code>/effort</code>，控制思考深度）、<code>opusplan</code> 的细节这里先不展开——把模型选对，对小白已经够用。需要深挖时查官方「模型配置」文档。</p></blockquote><blockquote><p>💡 一句话总结：<strong>难题 <code>opus</code>、日常 <code>sonnet</code>、杂活 <code>haiku</code></strong>；<code>default</code> 跟你的订阅层级走，Pro 默认 Sonnet、Max 默认 Opus。</p></blockquote><hr><h2 id="_06-动手-3-分钟确认「我在用谁」" tabindex="-1">06 动手：3 分钟确认「我在用谁」 <a class="header-anchor" href="#_06-动手-3-分钟确认「我在用谁」" aria-label="Permalink to &quot;06 动手：3 分钟确认「我在用谁」&quot;">​</a></h2><p>光看不练等于没看。下面这套命令，跑一遍你就能彻底搞清楚自己当前的身份和模型状态。<strong>全程在终端、然后在 Claude Code 界面里操作，不依赖任何复杂环境。</strong></p><p><strong>第一步：进 Claude Code。</strong> 随便找个目录，跑：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p><strong>第二步：查当前状态。</strong> 在 Claude Code 输入框里敲：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/status</span></span></code></pre></div><p>它会显示你的<strong>账户信息</strong>和<strong>当前生效的身份验证方式 / 模型</strong>。预期看到类似（具体字段随版本，以实际显示为准）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account: your@email.com (Max)</span></span>
<span class="line"><span>Auth: Claude subscription (OAuth)</span></span>
<span class="line"><span>Model: opus (Opus 4.8)</span></span></code></pre></div><p>如果这里 <code>Auth</code> 显示的是 API key、而你以为自己在用订阅——恭喜，你刚抓到了开头说的那个坑。</p><p><strong>第三步：看能用哪些模型 / 切一下。</strong> 输入：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/model</span></span></code></pre></div><p>会弹出模型选择器，列出 <code>opus</code> / <code>sonnet</code> / <code>haiku</code> 等可选项，上下选、回车确认。想直接切就：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/model sonnet</span></span></code></pre></div><p><strong>第四步（可选）：验证「订阅 vs API key」的优先级。</strong> 这一步能让你亲眼看见 04 节讲的规律。先退出 Claude Code，在终端里：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看看环境里有没有 API key 在「偷偷」盖过你的订阅</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $ANTHROPIC_API_KEY</span></span></code></pre></div><ul><li><strong>如果输出一串 <code>sk-ant-...</code></strong>：说明它正压着你的订阅。想用回订阅就 <code>unset ANTHROPIC_API_KEY</code>，再进 <code>claude</code> 跑 <code>/status</code> 复查，<code>Auth</code> 应该变回订阅。</li><li><strong>如果输出为空</strong>：你本来就在走订阅（或其它优先级更高的凭证），没问题。</li></ul><p>Windows（PowerShell）查环境变量用：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">echo $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ANTHROPIC_API_KEY</span></span></code></pre></div><p><strong>验收标准：</strong> 你能用 <code>/status</code> 一眼说出「我现在用的是订阅还是 API key、跑的是哪个模型」，并且能通过 <code>unset</code> + 复查，亲手切回订阅。做到了，这篇的核心目标就达成了。</p><hr><h2 id="_07-小结" tabindex="-1">07 小结 <a class="header-anchor" href="#_07-小结" aria-label="Permalink to &quot;07 小结&quot;">​</a></h2><p>这一篇就讲清了一件事：<strong>Claude Code 用什么身份连模型，以及这个身份怎么选、怎么切。</strong></p><table tabindex="0"><thead><tr><th>你的情况</th><th>怎么配</th><th>默认模型</th></tr></thead><tbody><tr><td>个人 Pro / Max</td><td>跑 <code>claude</code> → 浏览器 <code>/login</code></td><td>Pro→Sonnet，Max→Opus</td></tr><tr><td>脚本 / CI / 团队按量</td><td>Console 拿 key → 配 <code>ANTHROPIC_API_KEY</code></td><td>看具体设置</td></tr><tr><td>想切回订阅</td><td><code>unset ANTHROPIC_API_KEY</code> + <code>/status</code> 复查</td><td>—</td></tr></tbody></table><p>三个最该记住的点：</p><ul><li><strong>订阅在优先级最底层</strong>，环境里任何一个 API key / token 都会盖过它——被莫名扣费先查这个。</li><li><strong><code>/status</code> 是你的照妖镜</strong>：搞不清在用谁，敲它。</li><li><strong>模型按活儿挑</strong>：难题 <code>opus</code>、日常 <code>sonnet</code>，<code>default</code> 跟订阅层级走。</li></ul><p>你现在应该能：装好后正确登录、看懂自己在用哪个身份和模型、在订阅和 API key 之间来回切，并且不再被「明明登了订阅却扣 API 费」这种事坑到。</p><h2 id="下一篇预告" tabindex="-1">下一篇预告 <a class="header-anchor" href="#下一篇预告" aria-label="Permalink to &quot;下一篇预告&quot;">​</a></h2><p>到这儿你连的还是 <strong>Claude 官方的模型</strong>。但 Claude 在国内用，官方 API 不算友好——<strong>能不能让 Claude Code 跑 DeepSeek、通义千问、GLM 这些国产模型？</strong></p><p>能。秘密就在这篇反复出现、却一直没展开的那个环境变量——<code>ANTHROPIC_BASE_URL</code>：它不改「用哪个模型」，只改「请求发到哪」。下一篇 <strong>05 · 接入第三方 / 国产模型</strong>，就用它把 Claude Code 接到国产大模型上，省钱还不用魔法上网。</p><p>留个小思考给你：既然 API key 会盖过订阅，那把 <code>ANTHROPIC_BASE_URL</code> 指向国产平台、再配上对应的 key，Claude Code 是不是就「换芯」了？下一篇见分晓。</p><hr><p>接好了官方模型这条「主路」，下一篇咱们拐进国产模型这条「岔路」。</p>`,110)])])}const u=e(d,[["render",i]]);export{k as __pageData,u as default};
